const mapped = $('Map payload').first().json;
const api = $input.first().json;
const composeYaml = String(api.composeYaml ?? '').trim();
if (!composeYaml) {
  throw new Error(
    'Empty compose from deploy-webhook-compose: set N8N_COMPOSE_FETCH_SECRET in the n8n environment to match Supabase, and deploy the deploy-webhook-compose Edge Function.',
  );
}
return [{ json: { ...mapped, composeYaml } }];

const hook = $('Webhook').first().json;
const mapped = $('Merge stack compose').first().json;

function parseWebhookBody(h) {
  if (!h || h.body == null) return {};
  if (typeof h.body === 'string') {
    try {
      return JSON.parse(h.body);
    } catch {
      return {};
    }
  }
  if (typeof h.body === 'object' && !Array.isArray(h.body)) return { ...h.body };
  return {};
}

const wb = parseWebhookBody(hook);

const mergedEnv =
  mapped.env &&
  typeof mapped.env === 'object' &&
  !Array.isArray(mapped.env) &&
  Object.keys(mapped.env).length > 0
    ? mapped.env
    : wb.env && typeof wb.env === 'object' && !Array.isArray(wb.env)
      ? wb.env
      : {};

const j = {
  botDeploymentId: mapped.botDeploymentId ?? wb.botDeploymentId,
  customerLabel: mapped.customerLabel ?? wb.customerLabel,
  assignedUserId: mapped.assignedUserId ?? wb.assignedUserId,
  userId: mapped.userId ?? wb.userId,
  updateStackOnly: mapped.updateStackOnly ?? wb.updateStackOnly ?? false,
  env: mergedEnv,
  provider: {
    ...(typeof wb.provider === 'object' && wb.provider ? wb.provider : {}),
    ...(typeof mapped.provider === 'object' && mapped.provider ? mapped.provider : {}),
  },
  infra: {
    ...(typeof wb.infra === 'object' && wb.infra ? wb.infra : {}),
    ...(typeof mapped.infra === 'object' && mapped.infra ? mapped.infra : {}),
  },
  composeYaml: String(
    mapped.composeYaml ??
      mapped.dockerComposeYaml ??
      wb.composeYaml ??
      wb.dockerComposeYaml ??
      hook.composeYaml ??
      hook.dockerComposeYaml ??
      '',
  ).trim(),
  openclawBaseJson: mapped.openclawBaseJson ?? wb.openclawBaseJson ?? null,
};

function sanitizeSlug(s) {
  let t = String(s ?? '')
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '');
  if (!t) t = 'deployment';
  if (t.length > 48) t = t.slice(0, 48).replace(/-+$/, '');
  return t;
}

function formatEnvValue(val) {
  const str = String(val ?? '');
  if (/[\n\r"#=\s]/.test(str)) {
    return (
      '"' +
      str.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, '\\n') +
      '"'
    );
  }
  return str;
}

const vmIdRaw = j.infra?.providerVmId;
if (
  vmIdRaw === undefined ||
  vmIdRaw === null ||
  String(vmIdRaw).trim() === ''
) {
  throw new Error(
    'Missing infra.providerVmId: set Hostinger VM id in bot_deployment_infra (or deploy-bot-callback after provision).',
  );
}

const composeYaml = String(j.composeYaml ?? '').trim();
if (!composeYaml) {
  throw new Error(
    'Missing compose YAML in webhook body: redeploy deploy-bot Edge Function, save Stack template in Supabase, and check body.composeYaml / body.dockerComposeYaml in Webhook output.',
  );
}

function gatewayUrlToControlUiOrigin(urlRaw) {
  const u = String(urlRaw ?? '').trim();
  if (!u) return '';
  try {
    const ws = u.replace(/^wss:/i, 'https:').replace(/^ws:/i, 'http:');
    return new URL(ws).origin;
  } catch {
    return '';
  }
}
const envObj =
  j.env && typeof j.env === 'object' && !Array.isArray(j.env) ? j.env : {};
const _oj = j.openclawBaseJson;
if (_oj && typeof _oj === 'object' && !Array.isArray(_oj) && Object.keys(_oj).length > 0) {
  envObj.OPENCLAW_BASE_JSON_B64 = Buffer.from(JSON.stringify(_oj), 'utf8').toString('base64');
}
const _uiOrigin = gatewayUrlToControlUiOrigin(envObj.OPENCLAW_GATEWAY_URL);
if (_uiOrigin) envObj.OPENCLAW_CONTROL_UI_ORIGIN = _uiOrigin;
const lines = [];
for (const key of Object.keys(envObj).sort()) {
  const v = envObj[key];
  if (v === undefined || v === null) continue;
  if (typeof v === 'object') continue;
  if (!/^[A-Za-z_][A-Za-z0-9_]*$/.test(key)) continue;
  lines.push(key + '=' + formatEnvValue(v));
}
const environment = lines.join('\n');

const userKey = j.assignedUserId ?? j.userId ?? '';
const slugPart = sanitizeSlug(
  String(userKey).trim() || j.customerLabel || j.botDeploymentId,
);
const idSafe = String(j.botDeploymentId)
  .replace(/[^a-zA-Z0-9-]/g, '')
  .slice(0, 36);
const projectName = 'openclaw-' + slugPart + '__' + idSafe;

let base = String(j.provider?.vpsApiBaseUrl ?? '').replace(/\/+$/, '');
const vmSufx = '/virtual-machines';
while (base.toLowerCase().endsWith(vmSufx)) {
  base = base.slice(0, -vmSufx.length).replace(/\/+$/, '');
}
if (!base) {
  throw new Error(
    'Missing provider.vpsApiBaseUrl: Hostinger API root (e.g. https://developers.hostinger.com/api/vps/v1), not .../virtual-machines/.',
  );
}
const token = String(j.provider?.vpsApiToken ?? '').trim();
if (!token) {
  throw new Error('Missing provider.vpsApiToken.');
}

const dockerApiUrl =
  base + '/virtual-machines/' + String(vmIdRaw).trim() + '/docker';

return [
  {
    json: {
      dockerApiUrl,
      project_name: projectName,
      content: composeYaml,
      environment,
      bearerToken: token,
    },
  },
];

